1	// game-of-life.spec.ts
2	import { describe, it, expect } from "vitest";
3	import { nextGeneration } from "./game-of-life.js";
4	
5	describe("Game of Life - nextGeneration", () => {
6	  it("should return an empty array for an empty grid", () => {
7	    expect(nextGeneration([])).toEqual([]);
8	  });
9	  it("should let a single cell die (underpopulation: 0 neighbors)", () => {
10	    expect(nextGeneration([[0, 0]])).toEqual([]);
11	  });
12	  it("should let two neighboring cells die (underpopulation: 1 neighbor each)", () => {
13	    expect(
14	      nextGeneration([
15	        [0, 1],
16	        [1, 1],
17	      ])
18	    ).toEqual([]);
19	  });
20	  it("should keep a live cell with 2 live neighbors alive (survival)", () => {
21	    expect(
22	      nextGeneration([
23	        [0, 0],
24	        [0, 1],
25	        [0, 2],
26	      ])
27	    ).toContainEqual([0, 1]);
28	  });
29	  it("should keep a live cell with 3 live neighbors alive (survival)", () => {
30	    expect(
31	      nextGeneration([
32	        [0, 0],
33	        [1, 0],
34	        [2, 0],
35	        [1, 1],
36	      ])
37	    ).toContainEqual([1, 1]);
38	  });
39	  it("should let a live cell with 4 live neighbors die (overpopulation)", () => {
40	    expect(
41	      nextGeneration([
42	        [1, 1],
43	        [0, 1],
44	        [2, 1],
45	        [1, 0],
46	        [1, 2],
47	      ])
48	    ).not.toContainEqual([1, 1]);
49	  });
50	  it("should bring a dead cell with exactly 3 live neighbors to life (reproduction)", () => {
51	    expect(
52	      nextGeneration([
53	        [0, 0],
54	        [1, 0],
55	        [0, 1],
56	      ])
57	    ).toContainEqual([1, 1]);
58	  });
59	  it("should keep a block still life unchanged", () => {
60	    const block: [number, number][] = [
61	      [0, 0],
62	      [1, 0],
63	      [0, 1],
64	      [1, 1],
65	    ];
66	    const sortCells = (cells: [number, number][]) =>
67	      [...cells].sort(([ax, ay], [bx, by]) => ax - bx || ay - by);
68	    expect(sortCells(nextGeneration(block))).toEqual(sortCells(block));
69	  });
70	  it.todo(
71	    "should oscillate a vertical blinker to a horizontal blinker (negative coordinates)"
72	  );
73	});
74

1	export type Cell = [number, number];
2	
3	const neighborOffsets: Cell[] = [
4	  [-1, -1],
5	  [-1, 0],
6	  [-1, 1],
7	  [0, -1],
8	  [0, 1],
9	  [1, -1],
10	  [1, 0],
11	  [1, 1],
12	];
13	
14	const neighborsOf = ([x, y]: Cell): Cell[] =>
15	  neighborOffsets.map(([dx, dy]) => [x + dx, y + dy]);
16	
17	const isAlive = ([x, y]: Cell, cells: Cell[]): boolean =>
18	  cells.some(([cellX, cellY]) => cellX === x && cellY === y);
19	
20	const countLiveNeighbors = (cell: Cell, cells: Cell[]): number =>
21	  neighborsOf(cell).filter((neighbor) => isAlive(neighbor, cells)).length;
22	
23	const survives = (liveNeighbors: number): boolean =>
24	  liveNeighbors === 2 || liveNeighbors === 3;
25	
26	const unique = (cells: Cell[]): Cell[] => {
27	  const seen = new Set<string>();
28	  return cells.filter((cell) => {
29	    const key = cell.join(",");
30	    if (seen.has(key)) return false;
31	    seen.add(key);
32	    return true;
33	  });
34	};
35	
36	const deadNeighbors = (cells: Cell[]): Cell[] =>
37	  unique(cells.flatMap(neighborsOf).filter((cell) => !isAlive(cell, cells)));
38	
39	export const nextGeneration = (cells: Cell[]): Cell[] => {
40	  const survivors = cells.filter((cell) =>
41	    survives(countLiveNeighbors(cell, cells))
42	  );
43	  const births = deadNeighbors(cells).filter(
44	    (cell) => countLiveNeighbors(cell, cells) === 3
45	  );
46	  return [...survivors, ...births];
47	};
